UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Экструзия Верблюд — куполообразное лавовое тело между Авачинским и Корякским вулканами (53.26°N, 158.74°E). Высота ~1055 м. Сложена андезитовой лавой, выдавленной из жерла. Два округлых горба напоминают верблюда — отсюда название. Популярная цель однодневных экскурсий с базы «Три вулкана»: подъём 1,5–2 часа, панорама на оба вулкана и Авачинскую бухту. Евражки (земные белки) не боятся туристов.'
